//Time(rqtime)컬럼 hh:mm
scwin.timeFormatter = function (data) {
  if (!data) return "";

  // 1. 데이터를 문자열로 변환하고 공백 제거
  var str = data.toString().trim();

  // 2. 3자리인 경우(예: 900) 앞에 0을 붙여 4자리로 만듦
  // if (str.length === 3) {
  //     str = "0" + str;
  // }

  // 3. 4자리인 경우 "HH:mm" 형태로 포맷팅
  if (str.length === 3) {
    return str.substring(0, 2) + ":" + str.substring(2, 3);
  }
  if (str.length === 4) {
    return str.substring(0, 2) + ":" + str.substring(2, 4);
  }
  return str; // 그 외의 경우는 그대로 반환
};
